import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.io.IOException;

public class SecureFileRead {

    public static void main(String[] args) {
        if (args.length < 1) {
            System.out.println("Please provide a file name as a command line argument.");
            return;
        }

        String fileName = args[0]; // User input - file name provided as a command line argument

        try {
            Path filePath = Paths.get(fileName).toRealPath();

            if (!Files.isRegularFile(filePath)) {
                System.out.println("Specified path is not a valid file.");
                return;
            }

            byte[] fileData = Files.readAllBytes(filePath);
            System.out.println(new String(fileData));
        } catch (IOException e) {
            System.out.println("File not found or could not be read.");
        }
    }
}

### Explanation:
취약유형: Path Traversal
